  const updatedCampaigns = client.campaigns.map(campaign => {
    // Only update Facebook campaigns for this simulation
    if (campaign.platform !== 'facebook') return campaign;

    const variation = 1 + (Math.random() * 0.05 - 0.01); // Random variation between -1% and +4%

    return {
      ...campaign,
      metrics: {
        spend: parseFloat((campaign.metrics.spend * variation).toFixed(2)),
        impressions: Math.floor(campaign.metrics.impressions * variation),
        clicks: Math.floor(campaign.metrics.clicks * variation),
        conversions: Math.floor(campaign.metrics.conversions * variation),
        conversionValue: parseFloat((campaign.metrics.conversionValue * variation).toFixed(2)),
      }
    };
  });

  return {
    ...client,
    lastSync: 'Agora mesmo',
    campaigns: updatedCampaigns
  };
};

import React, { useState, useEffect } from 'react';
import { Client } from '../types';
import { X, Save, Lock, AlertCircle, CheckCircle } from 'lucide-react';

interface SettingsModalProps {
  client: Client;
  isOpen: boolean;
  onClose: () => void;
  onSave: (clientId: string, data: Partial<Client>) => void;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({ client, isOpen, onClose, onSave }) => {
  const [adAccountId, setAdAccountId] = useState(client.adAccountId || '');
  const [accessToken, setAccessToken] = useState(client.accessToken || '');
  const [status, setStatus] = useState<'idle' | 'saving' | 'success'>('idle');

  // Reset form when client changes
  useEffect(() => {
    setAdAccountId(client.adAccountId || '');
    setAccessToken(client.accessToken || '');
    setStatus('idle');
  }, [client, isOpen]);

  if (!isOpen) return null;

  const handleSave = () => {
    setStatus('saving');
    // Simulate API validation check
    setTimeout(() => {
      onSave(client.id, { adAccountId, accessToken });
      setStatus('success');
      setTimeout(() => {
        onClose();
        setStatus('idle');
      }, 1000);
    }, 800);
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden animate-fade-in-up">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex justify-between items-center">
          <div>
            <h3 className="font-bold text-slate-900">Configuração de Integração</h3>
            <p className="text-xs text-slate-500">Conecte a conta do {client.name}</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6 space-y-4">
          <div className="bg-blue-50 border border-blue-100 rounded-lg p-3 flex gap-3 text-sm text-blue-800">
            <AlertCircle className="w-5 h-5 flex-shrink-0 text-blue-600" />
            <p>Os dados são puxados automaticamente da API do Meta Ads. Insira as credenciais da conta específica deste cliente.</p>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">
              ID da Conta de Anúncios (Ad Account ID)
            </label>
            <div className="relative">
              <input 
                type="text" 
                value={adAccountId}
                onChange={(e) => setAdAccountId(e.target.value)}
                placeholder="act_123456789"
                className="w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              />
              <div className="absolute left-3 top-2.5 text-slate-400">
                <span className="text-xs font-bold">ID</span>
              </div>
            </div>
            <p className="text-xs text-slate-400 mt-1">Encontrado na URL do Gerenciador de Anúncios.</p>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">
              Token de Acesso (Access Token)
            </label>
            <div className="relative">
              <input 
                type="password" 
                value={accessToken}
                onChange={(e) => setAccessToken(e.target.value)}
                placeholder="EAAB..."
                className="w-full pl-10 pr-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              />
              <Lock className="w-4 h-4 text-slate-400 absolute left-3 top-3" />
            </div>
            <p className="text-xs text-slate-400 mt-1">Gerado no Meta for Developers.</p>
          </div>
        </div>

        <div className="bg-slate-50 px-6 py-4 border-t border-slate-200 flex justify-end">
          <button 
            onClick={handleSave}
            disabled={status === 'saving' || status === 'success'}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium text-white transition-all ${
              status === 'success' 
                ? 'bg-emerald-500' 
                : 'bg-indigo-600 hover:bg-indigo-700'
            }`}
          >
            {status === 'saving' ? (
              'Validando...'
            ) : status === 'success' ? (
              <>
                <CheckCircle className="w-4 h-4" />
