        clicks: parseInt(fbCamp.clicks || 0),
        conversions: getMetricValue(fbCamp.actions, 'purchase'), // foca em compras
        conversionValue: getMetricValue(fbCamp.action_values, 'purchase')
      };

      return {
        id: fbCamp.id,
        name: fbCamp.name,
        status: fbCamp.status === 'ACTIVE' ? 'active' : 'paused', // Simplificado
