import { Client, Campaign, Metrics } from "../types";

// Função auxiliar para extrair valores de arrays do Facebook (ex: actions, action_values)
const getMetricValue = (dataArray: any[], actionType: string = 'purchase'): number => {
  if (!dataArray || !Array.isArray(dataArray)) return 0;
  // Tenta achar 'purchase', se não achar, soma tudo (comportamento genérico)
  const item = dataArray.find((item: any) => item.action_type === actionType);
  if (item) return parseFloat(item.value);

  // Fallback: soma total se não especificar tipo ou não achar compra
  return dataArray.reduce((acc: number, curr: any) => acc + parseFloat(curr.value || 0), 0);
};

// Interface para o retorno da validação
export interface MetaAccountInfo {
  id: string;
  name: string;
  currency: string;
}

export const validateMetaConnection = async (adAccountId: string, accessToken: string): Promise<MetaAccountInfo> => {
  if (!adAccountId || !accessToken) {
    throw new Error("ID da Conta e Token são obrigatórios.");
  }

  // Mock check para demos
  if (accessToken === 'mock_token' || accessToken.length < 20) {
      await new Promise(resolve => setTimeout(resolve, 1000));
      return {
        id: adAccountId,
        name: "Conta de Simulação",
        currency: "BRL"
      };
  }

  const cleanActId = adAccountId.replace('act_', '').trim();
  const accountId = `act_${cleanActId}`;

  // Chamada leve para verificar acesso (pede nome, status e moeda)
  const url = `https://graph.facebook.com/v19.0/${accountId}?fields=name,account_status,currency&access_token=${accessToken}`;

  try {
    const response = await fetch(url);
    const json = await response.json();

    if (json.error) {
      console.error("Meta Validation Error:", json.error);
      const msg = json.error.message;

      if (json.error.code === 190) throw new Error("Token inválido ou expirado.");
      if (json.error.code === 100) throw new Error("ID da Conta de Anúncios inválido.");
      if (json.error.code === 200) throw new Error("Permissão negada. Verifique se o usuário do Token tem acesso a esta Conta de Anúncios.");

      throw new Error(msg);
    }

    return {
      id: json.id,
      name: json.name,
      currency: json.currency
    };
  } catch (error: any) {
    if (error.message.includes('Failed to fetch')) {
        throw new Error("Erro de conexão (Bloqueio CORS). Use uma extensão 'Allow CORS' para testar localmente.");
    }
    throw error;
  }
};

export const syncMetaAdsData = async (client: Client): Promise<Client> => {
  // Se não tiver credenciais, retorna erro
  if (!client.adAccountId || !client.accessToken) {
    throw new Error("Credenciais (ID ou Token) não configuradas.");
  }

  // Verifica se é um token falso/mock (opcional, para manter a demo funcionando se o usuário não tiver conta real)
  if (client.accessToken === 'mock_token' || client.accessToken.length < 20) {
     // Simulação (mantida para testes rápidos)
     await new Promise(resolve => setTimeout(resolve, 1500));
     const updatedCampaigns = client.campaigns.map(campaign => {
      if (campaign.platform !== 'facebook') return campaign;
      const variation = 1 + (Math.random() * 0.05 - 0.01);
      return {
        ...campaign,
        metrics: {
          spend: parseFloat((campaign.metrics.spend * variation).toFixed(2)),
          impressions: Math.floor(campaign.metrics.impressions * variation),
          clicks: Math.floor(campaign.metrics.clicks * variation),
          conversions: Math.floor(campaign.metrics.conversions * variation),
          conversionValue: parseFloat((campaign.metrics.conversionValue * variation).toFixed(2)),
        }
      };
    });
    return { ...client, lastSync: 'Simulação (Token Inválido)', campaigns: updatedCampaigns };
  }

  // CHAMADA REAL À API
  try {
    // Limpa o ID da conta para garantir formato 'act_NUMERO' ou apenas 'NUMERO'
    const cleanActId = client.adAccountId.replace('act_', '').trim();
    const accountId = `act_${cleanActId}`;

    // Campos solicitados à API
    const fields = 'id,name,status,objective,spend,impressions,clicks,cpc,ctr,actions,action_values,adsets{targeting},ads{creative{title,image_url,thumbnail_url}}';

    // Data Preset: 'this_month', 'last_30d', etc.
    const url = `https://graph.facebook.com/v19.0/${accountId}/campaigns?fields=${fields}&date_preset=this_month&access_token=${client.accessToken}`;

    const response = await fetch(url);
    const json = await response.json();

    if (json.error) {
      console.error("Meta API Error Details:", JSON.stringify(json.error, null, 2));

      const code = json.error.code;
      const msg = json.error.message;

      // Tratamento de erros específicos
      if (code === 190) {
        throw new Error("Token Expirado ou Inválido. Gere um novo token no Meta Developers.");
      }

      if (code === 200 && msg.includes('permission')) {
        throw new Error("Permissão Negada: O Token não tem permissão 'ads_read' ou o usuário não está vinculado a esta Conta de Anúncios.");
      }

      if (code === 100) {
         throw new Error("Parâmetro Inválido: Verifique se o ID da Conta de Anúncios está correto.");
      }

      throw new Error(`Erro Meta: ${msg}`);
    }

    // Mapear dados do Facebook para nosso formato
    const realCampaigns: Campaign[] = json.data.map((fbCamp: any) => {
      // Tentar pegar criativo do primeiro anúncio (simplificação)
      const firstAd = fbCamp.ads?.data?.[0];
      const creativeData = firstAd?.creative;

      const metrics: Metrics = {
        spend: parseFloat(fbCamp.spend || 0),
        impressions: parseInt(fbCamp.impressions || 0),
        clicks: parseInt(fbCamp.clicks || 0),
        conversions: getMetricValue(fbCamp.actions, 'purchase'), // foca em compras
        conversionValue: getMetricValue(fbCamp.action_values, 'purchase')
      };

      return {
        id: fbCamp.id,
        name: fbCamp.name,
        status: fbCamp.status === 'ACTIVE' ? 'active' : 'paused', // Simplificado
        platform: 'facebook',
        objective: fbCamp.objective || 'Desconhecido',
        audience: 'Público importado do Facebook', // A API de audience é complexa, deixamos genérico
        creative: {
          id: creativeData?.id || 'unknown',
          type: 'image',
          url: creativeData?.image_url || creativeData?.thumbnail_url || 'https://via.placeholder.com/150',
          headline: creativeData?.title || fbCamp.name
        },
        metrics: metrics
      };
    });

    // Mesclar campanhas reais com as de outras plataformas que já existiam (ex: Google/TikTok mockados)
    const otherPlatformCampaigns = client.campaigns.filter(c => c.platform !== 'facebook');

    return {
      ...client,
      lastSync: 'Agora mesmo (Via API)',
      campaigns: [...realCampaigns, ...otherPlatformCampaigns]
    };

  } catch (error: any) {
    console.error("Sync Error:", error);
    // Erro comum de CORS em localhost
    if (error.message.includes('Failed to fetch') || error.message.includes('NetworkError')) {
       throw new Error("Bloqueio de CORS: O navegador bloqueou a conexão. Use uma extensão 'Allow CORS' para testar localmente.");
    }
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
