          accessToken: accessToken,
          lastSync: 'Nunca',
          campaigns: [] // Começa vazio, precisa sincronizar
        };
        setSelectedClientId(newClient.id); // Seleciona o novo
        return [...prevClients, newClient];
      }
    });
  };

  const handleDeleteClient = (id: string) => {
    setClients(prevClients => {
      const filtered = prevClients.filter(c => c.id !== id);
      // Se apagamos o cliente selecionado, seleciona o primeiro disponível
      if (selectedClientId === id && filtered.length > 0) {
        setSelectedClientId(filtered[0].id);
      }
      return filtered;
    });
  };

  const handleSyncData = async () => {
    if (!selectedClient) return;

    setIsSyncing(true);
    setSyncError(null);
    try {
      const updatedClient = await syncMetaAdsData(selectedClient);
      setClients(prevClients => 
        prevClients.map(c => c.id === updatedClient.id ? updatedClient : c)
      );
    } catch (error: any) {
      setSyncError(error.message);
      // Auto-dismiss error after 3 seconds
      setTimeout(() => setSyncError(null), 3000);
    } finally {
      setIsSyncing(false);
    }
  };

  const openSettingsForNew = () => {
    setEditingClient(null); // Modo de criação
    setIsSettingsOpen(true);
  };

  if (clients.length === 0) {
    return (
       <div className="flex items-center justify-center min-h-screen bg-slate-50">
          <div className="text-center">
            <h2 className="text-2xl font-bold text-slate-800 mb-4">Bem-vindo ao AdsManager Pro</h2>
            <p className="text-slate-500 mb-6">Nenhuma conta conectada. Adicione sua primeira conta de anúncios.</p>
            <button 
              onClick={openSettingsForNew}
              className="bg-indigo-600 text-white px-6 py-3 rounded-lg font-medium hover:bg-indigo-700 transition-colors flex items-center gap-2 mx-auto"
            >
              <RefreshCw className="w-5 h-5" />
              Conectar Conta Facebook Ads
            </button>
            <SettingsModal
              initialClient={null}
              isOpen={isSettingsOpen}
              onClose={() => setIsSettingsOpen(false)}
              onSave={handleSaveAccount}
            />
          </div>
       </div>
    );
  }

  return (
    <div className="flex bg-slate-50 min-h-screen">
      <Sidebar 
        clients={clients} 
        selectedClientId={selectedClientId} 
        onSelectClient={setSelectedClientId} 
        onOpenSettings={openSettingsForNew}
        onDeleteClient={handleDeleteClient}
      />

      {/* Main Content */}
      <main className="ml-64 flex-1 p-8">

        {/* Top Bar */}
        <header className="flex justify-between items-center mb-8">
          <div>
            <div className="flex items-center gap-3">
               <h1 className="text-2xl font-bold text-slate-900">Dashboard de Campanhas</h1>
               {syncError && (
                 <span className="flex items-center text-xs text-rose-600 bg-rose-50 px-2 py-1 rounded-full border border-rose-100 animate-pulse">
                   <AlertTriangle className="w-3 h-3 mr-1" />
                   {syncError}
                 </span>
               )}
            </div>
            <div className="flex items-center gap-2 mt-1">
              <p className="text-slate-500 text-sm">
                Gerenciando <span className="font-semibold text-indigo-600">{selectedClient.name}</span>
              </p>
              <span className="text-slate-300">•</span>
              <p className="text-xs text-slate-400">
                Última sincronização: {selectedClient.lastSync || 'Nunca'}
              </p>
            </div>
          </div>
          <div className="flex gap-3">
            <button 
              onClick={handleSyncData}
              disabled={isSyncing}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium border transition-all ${
                isSyncing 
                  ? 'bg-slate-100 text-slate-400 border-slate-200 cursor-not-allowed' 
                  : 'bg-white text-slate-700 border-slate-200 hover:border-indigo-300 hover:text-indigo-600'
              }`}
            >
              <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
              {isSyncing ? 'Sincronizando...' : 'Atualizar Dados'}
            </button>

            <button className="flex items-center gap-2 bg-white border border-slate-200 text-slate-600 px-4 py-2 rounded-lg text-sm font-medium hover:bg-slate-50">
              <Calendar className="w-4 h-4" />
              Este Mês
            </button>
            <button className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-indigo-700 shadow-sm shadow-indigo-200">
              <Filter className="w-4 h-4" />
              Filtrar
            </button>
          </div>
        </header>

        {/* Overview Stats */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <StatCard 
            label="Investimento Total" 
            value={`R$ ${clientMetrics.spend.toLocaleString('pt-BR')}`} 
            trend={12.5} 
            icon={<DollarSign className="w-5 h-5" />}
          />
          <StatCard 
            label="ROAS (Retorno)" 
            value={`${roas}x`} 
            trend={-2.4} 
            icon={<BarChart2 className="w-5 h-5" />}
          />
          <StatCard 
            label="Conversões" 
            value={clientMetrics.conversions.toString()} 
            trend={8.1} 
            icon={<ShoppingBag className="w-5 h-5" />}
          />
          <StatCard 
            label="CTR Médio" 
            value={`${ctr}%`} 
            trend={0}
            neutral 
            icon={<MousePointer className="w-5 h-5" />}
          />
        </div>

        {/* Charts & Graphs Area */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm mb-8">
          <div className="flex justify-between items-center mb-6">
            <h3 className="font-bold text-slate-800">Performance: Custo vs Receita</h3>
          </div>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                <defs>
                  <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                  </linearGradient>
                  <linearGradient id="colorSpend" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#cbd5e1" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#cbd5e1" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} tickFormatter={(val) => `R$${val}`} />
                <CartesianGrid vertical={false} stroke="#f1f5f9" />
                <Tooltip 
                  contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} 
