                  <div className="absolute top-2 left-2">
                    {campaign.platform === 'facebook' && <span className="bg-blue-600 text-white text-[10px] font-bold px-2 py-1 rounded">FB</span>}
                    {campaign.platform === 'google' && <span className="bg-green-600 text-white text-[10px] font-bold px-2 py-1 rounded">G-ADS</span>}
                    {campaign.platform === 'tiktok' && <span className="bg-black text-white text-[10px] font-bold px-2 py-1 rounded">TT</span>}
                  </div>
                </div>

                {/* Info */}
                <div className="p-5 flex-1 flex flex-col justify-between">
                  <div>
                    <div className="flex justify-between items-start mb-2">
                      <h3 className="font-bold text-slate-900 group-hover:text-indigo-600 transition-colors line-clamp-1">{campaign.name}</h3>
                      <span className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase ${campaign.status === 'active' ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-500'}`}>
