                    <p className="text-xs text-slate-500 mb-4 line-clamp-1 flex items-center gap-1">
                      <Target className="w-3 h-3" /> {campaign.objective}
                    </p>

                    <div className="grid grid-cols-3 gap-4 border-t border-slate-100 pt-4">
                      <div>
                        <p className="text-[10px] text-slate-400 uppercase font-semibold">Gasto</p>
                        <p className="font-bold text-slate-800 text-sm">R$ {campaign.metrics.spend}</p>
                      </div>
                      <div>
                        <p className="text-[10px] text-slate-400 uppercase font-semibold">ROAS</p>
                        <p className={`font-bold text-sm ${
                          campaign.metrics.spend > 0 && (campaign.metrics.conversionValue / campaign.metrics.spend) > 2 
                          ? 'text-emerald-600' 
                          : 'text-amber-600'
                        }`}>
                          {campaign.metrics.spend > 0 ? (campaign.metrics.conversionValue / campaign.metrics.spend).toFixed(1) : '0'}x
                        </p>
                      </div>
                      <div>
                        <p className="text-[10px] text-slate-400 uppercase font-semibold">CTR</p>
                        <p className="font-bold text-slate-800 text-sm">
                          {campaign.metrics.impressions > 0 ? ((campaign.metrics.clicks / campaign.metrics.impressions) * 100).toFixed(1) : 0}%
                        </p>
                      </div>
                    </div>
                  </div>

                  <div className="mt-4 pt-3 border-t border-slate-50 flex items-center text-xs text-indigo-600 font-medium opacity-0 group-hover:opacity-100 transition-opacity">
                    Ver detalhes e IA <Eye className="w-3 h-3 ml-1" />
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>

      {/* Campaign Details Modal */}
      {selectedCampaign && (
        <CampaignDetails 
          campaign={selectedCampaign} 
          onClose={() => setSelectedCampaign(null)} 
        />
      )}

      {/* API Settings Modal */}
      <SettingsModal
        initialClient={editingClient}
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        onSave={handleSaveAccount}
      />
    </div>
  );
}

