import { Client, Campaign, Metrics } from "../types";

// Função auxiliar para extrair valores de arrays do Facebook (ex: actions, action_values)
const getMetricValue = (dataArray: any[], actionType: string = 'purchase'): number => {
  if (!dataArray || !Array.isArray(dataArray)) return 0;
  const item = dataArray.find((item: any) => item.action_type === actionType);
  if (item) return parseFloat(item.value);
  return 0;
};

// Interface para o retorno da validação
export interface MetaAccountInfo {
  id: string;
  name: string;
  currency: string;
}

export const validateMetaConnection = async (adAccountId: string, accessToken: string): Promise<MetaAccountInfo> => {
  if (!adAccountId || !accessToken) {
    throw new Error("ID da Conta e Token são obrigatórios.");
  }

  if (accessToken === 'mock_token' || accessToken.length < 20) {
      await new Promise(resolve => setTimeout(resolve, 1000));
      return {
        id: adAccountId.startsWith('act_') ? adAccountId : `act_${adAccountId}`,
        name: "Conta de Simulação",
        currency: "BRL"
      };
  }

  const cleanActId = adAccountId.replace('act_', '').trim();
  const accountId = `act_${cleanActId}`;

  const url = `https://graph.facebook.com/v19.0/${accountId}?fields=name,account_status,currency&access_token=${accessToken}`;

  try {
    const response = await fetch(url);
    const json = await response.json();

    if (json.error) {
      console.error("Meta Validation Error:", json.error);
      const msg = json.error.message;
      if (json.error.code === 190) throw new Error("Token inválido ou expirado.");
      if (json.error.code === 100) throw new Error("ID da Conta de Anúncios inválido.");
      if (json.error.code === 200) throw new Error("Permissão negada.");
      throw new Error(msg);
    }

    return {
      id: json.id, // O FB retorna o ID oficial 'act_...'
      name: json.name,
      currency: json.currency
    };
  } catch (error: any) {
    if (error.message.includes('Failed to fetch')) {
        throw new Error("Erro de conexão (CORS). Use uma extensão 'Allow CORS' no navegador.");
    }
    throw error;
  }
};

export const syncMetaAdsData = async (client: Client): Promise<Client> => {
  if (!client.adAccountId || !client.accessToken) {
    throw new Error("Credenciais não configuradas.");
  }

  if (client.accessToken === 'mock_token' || client.accessToken.length < 20) {
     await new Promise(resolve => setTimeout(resolve, 1000));
     return client; // Em simulação não altera nada
  }

  try {
    const accountId = client.adAccountId.startsWith('act_') ? client.adAccountId : `act_${client.adAccountId}`;

    // CORREÇÃO: Métricas devem ser pedidas via 'insights'
    // O campo 'insights' retorna as métricas agregadas do período
    const fields = 'id,name,status,objective,insights{spend,impressions,clicks,cpc,ctr,actions,action_values},adsets{targeting},ads{creative{title,image_url,thumbnail_url}}';

    const url = `https://graph.facebook.com/v19.0/${accountId}/campaigns?fields=${fields}&date_preset=this_month&access_token=${client.accessToken}`;

    const response = await fetch(url);
    const json = await response.json();

    if (json.error) {
      console.error("Meta API Sync Error:", json.error);
      if (json.error.code === 100) {
         throw new Error("Parâmetro Inválido: Erro na estrutura da query de métricas. Verifique as permissões do token.");
      }
      throw new Error(`Erro Meta: ${json.error.message}`);
    }

    const realCampaigns: Campaign[] = json.data.map((fbCamp: any) => {
      // Pega o primeiro item de insights (geralmente só vem 1 se não houver breakdown)
      const insights = fbCamp.insights?.data?.[0] || {};

      const firstAd = fbCamp.ads?.data?.[0];
      const creativeData = firstAd?.creative;

      const metrics: Metrics = {
        spend: parseFloat(insights.spend || 0),
        impressions: parseInt(insights.impressions || 0),
        clicks: parseInt(insights.clicks || 0),
        conversions: getMetricValue(insights.actions, 'purchase'),
        conversionValue: getMetricValue(insights.action_values, 'purchase')
      };

      return {
        id: fbCamp.id,
        name: fbCamp.name,
        status: fbCamp.status === 'ACTIVE' ? 'active' : 'paused',
        platform: 'facebook',
        objective: fbCamp.objective || 'Desconhecido',
        audience: 'Importado via API',
        creative: {
          id: creativeData?.id || 'unknown',
          type: 'image',
          url: creativeData?.image_url || creativeData?.thumbnail_url || 'https://via.placeholder.com/150',
          headline: creativeData?.title || fbCamp.name
        },
        metrics: metrics
      };
    });

    const otherPlatformCampaigns = client.campaigns.filter(c => c.platform !== 'facebook');

    return {
      ...client,
      lastSync: new Date().toLocaleTimeString('pt-BR'),
      campaigns: [...realCampaigns, ...otherPlatformCampaigns]
    };

  } catch (error: any) {
    console.error("Sync Error:", error);
    throw error;
  }
};

import React, { useState, useMemo } from 'react';
import { MOCK_CLIENTS } from './constants';
import { Sidebar } from './components/Sidebar';
import { StatCard } from './components/StatCard';
import { CampaignDetails } from './components/CampaignDetails';
import { SettingsModal } from './components/SettingsModal';
import { Client, Campaign } from './types';
import { Search, Filter, Calendar, BarChart2, DollarSign, MousePointer, ShoppingBag, Eye, Target, RefreshCw, AlertTriangle } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { syncMetaAdsData, MetaAccountInfo } from './services/metaService';

function App() {
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [selectedClientId, setSelectedClientId] = useState<string>(MOCK_CLIENTS[0].id);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);

  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  const selectedClient = clients.find(c => c.id === selectedClientId) || clients[0];

  const clientMetrics = useMemo(() => {
    if (!selectedClient) return { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 };
    return selectedClient.campaigns.reduce((acc, curr) => {
      acc.spend += curr.metrics.spend;
      acc.impressions += curr.metrics.impressions;
      acc.clicks += curr.metrics.clicks;
      acc.conversions += curr.metrics.conversions;
      acc.revenue += curr.metrics.conversionValue;
      return acc;
    }, { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 });
  }, [selectedClient]);

  const roas = clientMetrics.spend > 0 ? (clientMetrics.revenue / clientMetrics.spend).toFixed(2) : '0.00';
  const ctr = clientMetrics.impressions > 0 ? ((clientMetrics.clicks / clientMetrics.impressions) * 100).toFixed(2) : '0.00';

  const chartData = [
    { name: '01 Set', spend: clientMetrics.spend * 0.1, revenue: clientMetrics.revenue * 0.08 },
    { name: '05 Set', spend: clientMetrics.spend * 0.2, revenue: clientMetrics.revenue * 0.15 },
    { name: '10 Set', spend: clientMetrics.spend * 0.4, revenue: clientMetrics.revenue * 0.35 },
    { name: '15 Set', spend: clientMetrics.spend * 0.6, revenue: clientMetrics.revenue * 0.65 },
    { name: '20 Set', spend: clientMetrics.spend * 0.8, revenue: clientMetrics.revenue * 0.75 },
    { name: '25 Set', spend: clientMetrics.spend * 0.9, revenue: clientMetrics.revenue * 0.9 },
    { name: '30 Set', spend: clientMetrics.spend, revenue: clientMetrics.revenue },
  ];

  const handleSaveAccount = (data: { adAccountId: string; accessToken: string; accountInfo: MetaAccountInfo }) => {
    const { accessToken, accountInfo } = data;
    const officialId = accountInfo.id; // Usar o ID retornado pela API (act_...)

    setClients(prevClients => {
      const existingClientIndex = prevClients.findIndex(c => 
        (c.adAccountId && c.adAccountId === officialId) ||
        (editingClient && c.id === editingClient.id)
      );

      if (existingClientIndex >= 0) {
        const updatedClients = [...prevClients];
        updatedClients[existingClientIndex] = {
          ...updatedClients[existingClientIndex],
          name: accountInfo.name,
          adAccountId: officialId,
          accessToken: accessToken,
          lastSync: 'Configuração Atualizada'
        };
        setSelectedClientId(updatedClients[existingClientIndex].id);
        return updatedClients;
      } else {
        const newClient: Client = {
          id: `c_${Date.now()}`,
          name: accountInfo.name,
          industry: 'Geral',
          avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(accountInfo.name)}&background=random`,
          adAccountId: officialId,
          accessToken: accessToken,
          lastSync: 'Aguardando Sinc.',
          campaigns: []
        };
        setSelectedClientId(newClient.id);
        return [...prevClients, newClient];
      }
    });
  };

  const handleDeleteClient = (id: string) => {
    setClients(prevClients => {
      const filtered = prevClients.filter(c => c.id !== id);
      if (selectedClientId === id && filtered.length > 0) {
        setSelectedClientId(filtered[0].id);
      }
      return filtered;
    });
  };

  const handleSyncData = async () => {
    if (!selectedClient || !selectedClient.adAccountId) return;

    setIsSyncing(true);
    setSyncError(null);
    try {
      const updatedClient = await syncMetaAdsData(selectedClient);
      setClients(prevClients => 
        prevClients.map(c => c.id === updatedClient.id ? updatedClient : c)
      );
    } catch (error: any) {
      setSyncError(error.message);
      setTimeout(() => setSyncError(null), 5000);
    } finally {
      setIsSyncing(false);
    }
  };

  const openSettingsForNew = () => {
    setEditingClient(null);
    setIsSettingsOpen(true);
  };

  if (clients.length === 0) {
    return (
       <div className="flex items-center justify-center min-h-screen bg-slate-50">
          <div className="text-center">
            <h2 className="text-2xl font-bold text-slate-800 mb-4">Bem-vindo ao AdsManager Pro</h2>
            <p className="text-slate-500 mb-6">Nenhuma conta conectada. Adicione sua primeira conta de anúncios.</p>
            <button 
              onClick={openSettingsForNew}
              className="bg-indigo-600 text-white px-6 py-3 rounded-lg font-medium hover:bg-indigo-700 transition-colors flex items-center gap-2 mx-auto"
            >
              <RefreshCw className="w-5 h-5" />
              Conectar Conta Facebook Ads
            </button>
            <SettingsModal
              initialClient={null}
              isOpen={isSettingsOpen}
              onClose={() => setIsSettingsOpen(false)}
              onSave={handleSaveAccount}
            />
          </div>
       </div>
    );
  }

  return (
    <div className="flex bg-slate-50 min-h-screen">
      <Sidebar 
        clients={clients} 
        selectedClientId={selectedClientId} 
        onSelectClient={setSelectedClientId} 
        onOpenSettings={openSettingsForNew}
        onDeleteClient={handleDeleteClient}
      />

      <main className="ml-64 flex-1 p-8">
        <header className="flex justify-between items-center mb-8">
          <div>
            <div className="flex items-center gap-3">
