const getMetricValue = (dataArray: any[], actionType: string = 'purchase'): number => {
  if (!dataArray || !Array.isArray(dataArray)) return 0;
  const item = dataArray.find((item: any) => item.action_type === actionType);
  if (item) return parseFloat(item.value);
  return 0;
};

const mapInsightsToMetrics = (insightsData: any): Metrics => {
  const insights = insightsData?.data?.[0] || {};
  return {
    spend: parseFloat(insights.spend || 0),
    impressions: parseInt(insights.impressions || 0),
    reach: parseInt(insights.reach || 0),
    frequency: parseFloat(insights.frequency || 0),
    cpm: parseFloat(insights.cpm || 0),
    clicks: parseInt(insights.clicks || 0),
    conversions: getMetricValue(insights.actions, 'purchase'),
    conversionValue: getMetricValue(insights.action_values, 'purchase')
  };
};

