export const syncMetaAdsData = async (client: Client): Promise<Client> => {
  if (!client.adAccountId || !client.accessToken) throw new Error("Credenciais não configuradas.");

  try {
    const accountId = client.adAccountId.startsWith('act_') ? client.adAccountId : `act_${client.adAccountId}`;

    // Deep query: Campaign -> AdSets -> Ads
    const fields = 'id,name,status,objective,daily_budget,lifetime_budget,start_time,stop_time,' + 
                   'insights{spend,impressions,reach,frequency,cpm,clicks,actions,action_values},' +
                   'adsets{id,name,status,daily_budget,lifetime_budget,targeting,insights{spend,impressions,reach,frequency,cpm,clicks,actions,action_values},' +
                   'ads{id,name,status,creative{id,title,image_url,thumbnail_url},insights{spend,impressions,reach,frequency,cpm,clicks,actions,action_values}}}';

    const url = `https://graph.facebook.com/v19.0/${accountId}/campaigns?fields=${fields}&date_preset=this_month&access_token=${client.accessToken}`;

    const response = await fetch(url);
    const json = await response.json();

    if (json.error) throw new Error(`Erro Meta: ${json.error.message}`);

    const realCampaigns: Campaign[] = json.data.map((fbCamp: any) => {
      const campMetrics = mapInsightsToMetrics(fbCamp.insights);

      const adSets: AdSet[] = (fbCamp.adsets?.data || []).map((fbAdSet: any) => {
        const adSetMetrics = mapInsightsToMetrics(fbAdSet.insights);

        const ads: Ad[] = (fbAdSet.ads?.data || []).map((fbAd: any) => {
          const adMetrics = mapInsightsToMetrics(fbAd.insights);
          const creative: Creative = {
            id: fbAd.creative?.id || 'unknown',
            type: 'image',
            url: fbAd.creative?.image_url || fbAd.creative?.thumbnail_url || 'https://via.placeholder.com/150',
            headline: fbAd.creative?.title || fbAd.name
          };

          return {
            id: fbAd.id,
            name: fbAd.name,
            status: fbAd.status === 'ACTIVE' ? 'active' : 'paused',
            creative,
            metrics: adMetrics
          };
        });

        return {
          id: fbAdSet.id,
          name: fbAdSet.name,
          status: fbAdSet.status === 'ACTIVE' ? 'active' : 'paused',
          budget: fbAdSet.daily_budget ? parseFloat(fbAdSet.daily_budget) / 100 : (fbAdSet.lifetime_budget ? parseFloat(fbAdSet.lifetime_budget) / 100 : 0),
          budgetType: fbAdSet.daily_budget ? 'DAILY' : 'LIFETIME',
          audience: JSON.stringify(fbAdSet.targeting) || 'Público Definido no Meta',
          metrics: adSetMetrics,
          ads
        };
      });

      // Default creative/audience for backward compatibility in main list
      const firstAdSet = adSets[0];
      const firstAd = firstAdSet?.ads[0];

      return {
        id: fbCamp.id,
        name: fbCamp.name,
        status: fbCamp.status === 'ACTIVE' ? 'active' : 'paused',
        platform: 'facebook',
        objective: fbCamp.objective,
        metrics: campMetrics,
        budget: fbCamp.daily_budget ? parseFloat(fbCamp.daily_budget) / 100 : (fbCamp.lifetime_budget ? parseFloat(fbCamp.lifetime_budget) / 100 : 0),
        budgetType: fbCamp.daily_budget ? 'DAILY' : 'LIFETIME',
        startTime: fbCamp.start_time,
        endTime: fbCamp.stop_time,
        adSets,
        creative: firstAd?.creative || { id: '0', type: 'image', url: 'https://via.placeholder.com/150', headline: fbCamp.name },
        audience: firstAdSet?.audience || 'Vários Públicos'
      };
    });

    return {
      ...client,
      lastSync: new Date().toLocaleTimeString('pt-BR'),
      campaigns: realCampaigns
    };

  } catch (error: any) {
    console.error("Sync Error:", error);
    throw error;
  }
};

