  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex justify-end">
      <div className="w-full max-w-5xl bg-slate-50 h-full shadow-2xl overflow-hidden animate-slide-in-right border-l border-slate-200 flex flex-col">

