            <div className="flex items-center gap-4">
              <div className="p-3 bg-indigo-50 text-indigo-600 rounded-xl">
                 <Layers className="w-6 h-6" />
              </div>
              <div>
                <div className="flex items-center gap-2 mb-0.5">
                  <span className={`w-2.5 h-2.5 rounded-full ${campaign.status === 'active' ? 'bg-emerald-500' : 'bg-slate-400'}`}></span>
                  <span className="text-[10px] uppercase tracking-widest text-slate-400 font-black">{campaign.platform} • {campaign.objective}</span>
                </div>
                <h2 className="text-xl font-black text-slate-900 tracking-tight">{campaign.name}</h2>
