import { syncMetaAdsData, MetaAccountInfo } from './services/metaService';

function App() {
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [selectedClientId, setSelectedClientId] = useState<string>(MOCK_CLIENTS[0].id);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);

  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  const selectedClient = clients.find(c => c.id === selectedClientId) || clients[0];

  const clientMetrics = useMemo(() => {
    if (!selectedClient) return { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 };
    return selectedClient.campaigns.reduce((acc, curr) => {
      acc.spend += curr.metrics.spend;
      acc.impressions += curr.metrics.impressions;
      acc.clicks += curr.metrics.clicks;
      acc.conversions += curr.metrics.conversions;
      acc.revenue += curr.metrics.conversionValue;
      return acc;
    }, { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 });
  }, [selectedClient]);

  const roas = clientMetrics.spend > 0 ? (clientMetrics.revenue / clientMetrics.spend).toFixed(2) : '0.00';
  const ctr = clientMetrics.impressions > 0 ? ((clientMetrics.clicks / clientMetrics.impressions) * 100).toFixed(2) : '0.00';

  const chartData = [
    { name: '01 Set', spend: clientMetrics.spend * 0.1, revenue: clientMetrics.revenue * 0.08 },
    { name: '05 Set', spend: clientMetrics.spend * 0.2, revenue: clientMetrics.revenue * 0.15 },
    { name: '10 Set', spend: clientMetrics.spend * 0.4, revenue: clientMetrics.revenue * 0.35 },
    { name: '15 Set', spend: clientMetrics.spend * 0.6, revenue: clientMetrics.revenue * 0.65 },
    { name: '20 Set', spend: clientMetrics.spend * 0.8, revenue: clientMetrics.revenue * 0.75 },
    { name: '25 Set', spend: clientMetrics.spend * 0.9, revenue: clientMetrics.revenue * 0.9 },
    { name: '30 Set', spend: clientMetrics.spend, revenue: clientMetrics.revenue },
  ];

  const handleSaveAccount = (data: { adAccountId: string; accessToken: string; accountInfo: MetaAccountInfo }) => {
    const { accessToken, accountInfo } = data;
    const officialId = accountInfo.id;

    setClients(prevClients => {
      const existingClientIndex = prevClients.findIndex(c => 
        (c.adAccountId && c.adAccountId === officialId) ||
        (editingClient && c.id === editingClient.id)
      );

      if (existingClientIndex >= 0) {
        const updatedClients = [...prevClients];
        updatedClients[existingClientIndex] = {
          ...updatedClients[existingClientIndex],
          name: accountInfo.name,
          adAccountId: officialId,
          accessToken: accessToken,
          lastSync: 'Configuração Atualizada'
        };
        setSelectedClientId(updatedClients[existingClientIndex].id);
        return updatedClients;
      } else {
        const newClient: Client = {
          id: `c_${Date.now()}`,
          name: accountInfo.name,
          industry: 'Geral',
          avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(accountInfo.name)}&background=random`,
          adAccountId: officialId,
          accessToken: accessToken,
          lastSync: 'Aguardando Sinc.',
          campaigns: []
        };
        setSelectedClientId(newClient.id);
        return [...prevClients, newClient];
      }
    });
  };

  const handleDeleteClient = (id: string) => {
    setClients(prevClients => {
      const filtered = prevClients.filter(c => c.id !== id);
      if (selectedClientId === id && filtered.length > 0) {
        setSelectedClientId(filtered[0].id);
      }
      return filtered;
    });
  };

  const handleSyncData = async () => {
    if (!selectedClient || !selectedClient.adAccountId) return;
    setIsSyncing(true);
    setSyncError(null);
    try {
      const updatedClient = await syncMetaAdsData(selectedClient);
      setClients(prevClients => 
        prevClients.map(c => c.id === updatedClient.id ? updatedClient : c)
      );
    } catch (error: any) {
      setSyncError(error.message);
      setTimeout(() => setSyncError(null), 5000);
    } finally {
      setIsSyncing(false);
    }
  };

  const openSettingsForNew = () => {
    setEditingClient(null);
    setIsSettingsOpen(true);
  };

  return (
    <div className="flex bg-slate-50 min-h-screen">
      <Sidebar 
        clients={clients} 
        selectedClientId={selectedClientId} 
        onSelectClient={setSelectedClientId} 
        onOpenSettings={openSettingsForNew}
        onDeleteClient={handleDeleteClient}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      <main className="flex-1 w-full lg:ml-64 transition-all duration-300 overflow-x-hidden">
        {/* Mobile Navbar */}
        <div className="lg:hidden flex items-center justify-between p-4 bg-white border-b border-slate-200 sticky top-0 z-30">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 hover:bg-slate-100 rounded-lg">
             <Menu className="w-6 h-6 text-slate-600" />
          </button>
          <div className="flex flex-col items-center">
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cliente Selecionado</span>
             <h4 className="text-xs font-black text-indigo-600">{selectedClient.name}</h4>
          </div>
          <button onClick={handleSyncData} className="p-2 text-indigo-600">
             <RefreshCw className={`w-5 h-5 ${isSyncing ? 'animate-spin' : ''}`} />
          </button>
        </div>

        <div className="p-4 md:p-8 space-y-8">
          <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex items-center gap-3">
                 <h1 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">Painel de Tráfego</h1>
                 {syncError && (
                   <span className="hidden md:flex items-center text-[10px] font-black text-rose-600 bg-rose-50 px-3 py-1 rounded-full border border-rose-100 uppercase">
                     <AlertTriangle className="w-3 h-3 mr-1" /> Erro
                   </span>
                 )}
              </div>
              <p className="text-xs md:text-sm text-slate-500 font-medium mt-1">
                Visualizando resultados de <span className="font-bold text-indigo-600">{selectedClient.name}</span>
              </p>
            </div>

            <div className="flex flex-wrap gap-2 w-full md:w-auto">
              <button 
                onClick={handleSyncData}
                disabled={isSyncing || !selectedClient.adAccountId}
                className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-4 py-2.5 rounded-xl text-xs font-black uppercase shadow-lg shadow-indigo-100 active:scale-95 transition-all"
              >
                <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
                {isSyncing ? 'Sincronizando' : 'Atualizar'}
              </button>
              <button className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-white border border-slate-200 text-slate-600 px-4 py-2.5 rounded-xl text-xs font-black uppercase">
                <Calendar className="w-4 h-4" /> Este Mês
              </button>
            </div>
          </header>

          {/* Quick Metrics Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
            <StatCard label="Investimento" value={`R$ ${clientMetrics.spend.toLocaleString('pt-BR')}`} trend={12} icon={<DollarSign />} />
            <StatCard label="ROAS" value={`${roas}x`} trend={-2} icon={<BarChart2 />} />
            <StatCard label="Conversões" value={clientMetrics.conversions.toString()} trend={8} icon={<ShoppingBag />} />
            <StatCard label="CTR Médio" value={`${ctr}%`} neutral icon={<MousePointer />} />
          </div>

          {/* Main Chart Section */}
          <div className="bg-white p-4 md:p-8 rounded-[32px] border border-slate-200 shadow-sm overflow-hidden">
            <div className="flex justify-between items-center mb-8">
              <h3 className="font-black text-slate-900 uppercase tracking-widest text-xs flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-indigo-600" /> Fluxo de Performance
              </h3>
            </div>
            <div className="h-[250px] md:h-[350px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                  <YAxis hide />
                  <CartesianGrid vertical={false} stroke="#f8fafc" />
                  <Tooltip contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} />
                  <Area type="monotone" dataKey="revenue" stroke="#4f46e5" fillOpacity={1} fill="url(#colorRevenue)" strokeWidth={4} />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
              <h2 className="text-xl font-black text-slate-900 tracking-tight">Campanhas Ativas</h2>
              <div className="relative w-full md:w-72">
                 <input 
                  type="text" 
                  placeholder="Filtrar campanha..." 
                  className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl text-xs font-bold focus:outline-none focus:ring-2 focus:ring-indigo-500 shadow-sm"
                 />
                 <Search className="w-4 h-4 text-slate-400 absolute left-3.5 top-1/2 -translate-y-1/2" />
              </div>
            </div>

            {selectedClient.campaigns.length === 0 ? (
              <div className="bg-white rounded-3xl p-12 text-center border-2 border-slate-100 border-dashed">
                <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Nenhuma campanha encontrada para este cliente.</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-4 md:gap-6">
                {selectedClient.campaigns.map((campaign) => (
                  <div 
                    key={campaign.id} 
                    onClick={() => setSelectedCampaign(campaign)}
                    className="bg-white rounded-[28px] border border-slate-200 shadow-sm hover:shadow-xl hover:border-indigo-300 transition-all cursor-pointer group flex flex-col sm:flex-row overflow-hidden"
                  >
                    <div className="w-full sm:w-44 h-44 sm:h-auto bg-slate-100 flex-shrink-0 relative overflow-hidden">
                      <img src={campaign.creative.url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                      <span className="absolute top-3 left-3 bg-slate-900 text-white text-[8px] font-black px-2 py-1 rounded-lg uppercase tracking-widest">{campaign.platform}</span>
                    </div>

                    <div className="p-6 flex-1 flex flex-col justify-between bg-white">
                      <div>
                        <div className="flex justify-between items-start mb-2 gap-2">
                          <h3 className="font-black text-slate-900 text-sm group-hover:text-indigo-600 transition-colors line-clamp-1">{campaign.name}</h3>
                          <span className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase flex-shrink-0 ${campaign.status === 'active' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}>
                            {campaign.status}
                          </span>
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase flex items-center gap-1 mb-4">
                          <Target className="w-3 h-3 text-indigo-500" /> {campaign.objective}
                        </p>

                        <div className="grid grid-cols-3 gap-2 pt-4 border-t border-slate-50">
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">Gasto</p>
                            <p className="font-black text-slate-900 text-xs">R$ {campaign.metrics.spend.toLocaleString('pt-BR')}</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">ROAS</p>
                            <p className="font-black text-indigo-600 text-xs">{(campaign.metrics.conversionValue / (campaign.metrics.spend || 1)).toFixed(1)}x</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">CTR</p>
                            <p className="font-black text-slate-900 text-xs">{((campaign.metrics.clicks / (campaign.metrics.impressions || 1)) * 100).toFixed(1)}%</p>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </main>

      {selectedCampaign && (
        <CampaignDetails 
          campaign={selectedCampaign} 
          onClose={() => setSelectedCampaign(null)} 
        />
      )}

      <SettingsModal
        initialClient={editingClient}
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        onSave={handleSaveAccount}
      />
    </div>
  );
}

export default App;

import React, { useState, useMemo } from 'react';
import { Campaign, AdSet, Ad, DemographicData } from '../types';
import { X, Target, MousePointer, DollarSign, Award, Activity, Sparkles, Loader2, Users, Eye, BarChart3, TrendingUp, Calendar, CreditCard, Layers, LayoutGrid, ListFilter, Play, Timer, Percent, BarChart, MapPin, Search, UserCheck, UserPlus, Users2 } from 'lucide-react';
import { analyzeCampaignPerformance } from '../services/geminiService';
import { BarChart as ReBarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as ReTooltip, ResponsiveContainer, Legend } from 'recharts';

interface CampaignDetailsProps {
  campaign: Campaign;
  onClose: () => void;
}

type Tab = 'overview' | 'adsets' | 'ads';

export const CampaignDetails: React.FC<CampaignDetailsProps> = ({ campaign, onClose }) => {
  const [activeTab, setActiveTab] = useState<Tab>('overview');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const { metrics, adSets } = campaign;

  const costPerResult = metrics.messages && metrics.messages > 0 ? (metrics.spend / metrics.messages).toFixed(2) : (metrics.conversions > 0 ? (metrics.spend / metrics.conversions).toFixed(2) : '0.00');

  const demographicChartData = useMemo(() => {
    if (!metrics.demographics || metrics.demographics.length === 0) return [];
    const ageGroups = ['13-17', '18-24', '25-34', '35-44', '45-54', '55-64', '65+'];
    return ageGroups.map(age => {
      const male = metrics.demographics?.find(d => d.age === age && d.gender === 'male')?.results || 0;
      const female = metrics.demographics?.find(d => d.age === age && d.gender === 'female')?.results || 0;
      return { age, Homens: male, Mulheres: female };
    });
  }, [metrics.demographics]);

  const handleAnalyze = async () => {
    setLoading(true);
    const result = await analyzeCampaignPerformance(campaign);
    setAnalysis(result);
    setLoading(false);
  };

  const allAds: Ad[] = adSets.flatMap(as => as.ads);

  const formatVideoTime = (seconds: number) => {
    const min = Math.floor(seconds / 60);
    const sec = Math.floor(seconds % 60);
    return `${min.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}`;
  };

  const renderAudienceDetails = (audienceStr: string) => {
    try {
      const t = JSON.parse(audienceStr);
      const items = [];
      if (t.targeting_id) items.push({ icon: <UserCheck className="w-3 h-3"/>, label: "Público Salvo", value: `ID: ${t.targeting_id}` });
      if (t.custom_audiences) {
        t.custom_audiences.forEach((ca: any) => {
          items.push({ icon: <UserPlus className="w-3 h-3 text-purple-500"/>, label: "Personalizado", value: ca.name || `ID: ${ca.id}` });
        });
      }
      const geo = t.geo_locations?.countries?.join(', ') || 'Brasil';
      items.push({ icon: <MapPin className="w-3 h-3"/>, label: "Local", value: geo });
      items.push({ icon: <Users2 className="w-3 h-3"/>, label: "Idade", value: `${t.age_min || 18} - ${t.age_max || '65+'}` });

      return (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 mt-3">
          {items.map((item, idx) => (
            <div key={idx} className="flex items-center gap-2 bg-white border border-slate-100 px-3 py-2 rounded-xl">
               <span className="text-slate-400">{item.icon}</span>
               <span className="text-[10px] font-black text-slate-400 uppercase">{item.label}:</span>
               <span className="text-[11px] font-bold text-slate-700 truncate flex-1">{item.value}</span>
            </div>
          ))}
        </div>
      );
    } catch {
      return <p className="text-xs text-slate-500 mt-2 italic font-medium">{audienceStr}</p>;
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[60] flex justify-end">
      <div className="w-full sm:max-w-5xl bg-slate-50 h-full shadow-2xl overflow-hidden animate-slide-in-right border-l border-slate-200 flex flex-col">

        {/* Responsive Header */}
        <div className="p-4 md:p-6 bg-white border-b border-slate-200 shadow-sm flex-shrink-0 z-30">
          <div className="flex justify-between items-start mb-6">
            <div className="flex items-center gap-3">
              <div className="p-2.5 md:p-3 bg-indigo-50 text-indigo-600 rounded-xl">
                 <Layers className="w-5 h-5 md:w-6 h-6" />
              </div>
              <div className="max-w-[200px] md:max-w-md">
                <div className="flex items-center gap-2 mb-0.5">
                  <span className={`w-2 h-2 rounded-full ${campaign.status === 'active' ? 'bg-emerald-500' : 'bg-slate-300'}`}></span>
                  <span className="text-[9px] md:text-[10px] uppercase tracking-widest text-slate-400 font-black truncate">{campaign.platform} • {campaign.objective}</span>
                </div>
                <h2 className="text-lg md:text-xl font-black text-slate-900 tracking-tight truncate">{campaign.name}</h2>
              </div>
            </div>
            <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-400">
              <X className="w-6 h-6" />
            </button>
          </div>

          <div className="flex gap-1 bg-slate-100 p-1 rounded-xl w-full md:w-fit overflow-x-auto no-scrollbar">
            <button onClick={() => setActiveTab('overview')} className={`flex items-center justify-center gap-2 px-4 md:px-6 py-2 rounded-lg text-xs md:text-sm font-black transition-all whitespace-nowrap ${activeTab === 'overview' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
              <Activity className="w-4 h-4" /> Visão Geral
            </button>
            <button onClick={() => setActiveTab('adsets')} className={`flex items-center justify-center gap-2 px-4 md:px-6 py-2 rounded-lg text-xs md:text-sm font-black transition-all whitespace-nowrap ${activeTab === 'adsets' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
              <Users className="w-4 h-4" /> Conjuntos
            </button>
            <button onClick={() => setActiveTab('ads')} className={`flex items-center justify-center gap-2 px-4 md:px-6 py-2 rounded-lg text-xs md:text-sm font-black transition-all whitespace-nowrap ${activeTab === 'ads' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>
              <LayoutGrid className="w-4 h-4" /> Anúncios
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-8 pb-32">

          {activeTab === 'overview' && (
            <div className="space-y-6 md:space-y-8 animate-fade-in">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6">
                <div className="bg-white p-5 md:p-6 rounded-3xl border border-slate-200 shadow-sm">
                  <p className="text-[9px] font-black text-slate-400 uppercase mb-2">Total Gasto</p>
                  <p className="text-2xl md:text-3xl font-black text-slate-900">R$ {metrics.spend.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
                </div>
                <div className="bg-indigo-600 p-5 md:p-6 rounded-3xl text-white shadow-xl shadow-indigo-100">
                  <p className="text-[9px] font-black text-indigo-200 uppercase mb-2">Resultados</p>
                  <p className="text-2xl md:text-3xl font-black">{metrics.messages || metrics.conversions || 0}</p>
                </div>
                <div className="bg-white p-5 md:p-6 rounded-3xl border border-slate-200 shadow-sm">
                  <p className="text-[9px] font-black text-slate-400 uppercase mb-2">Custo p/ Resultado</p>
                  <p className="text-2xl md:text-3xl font-black text-slate-900">R$ {parseFloat(costPerResult).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
                </div>
              </div>

              {/* DEMOGRAPHIC CHART */}
              <div className="bg-white p-6 md:p-8 rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                <div className="mb-6 md:mb-8">
                  <h3 className="font-black text-slate-900 text-base md:text-lg uppercase tracking-tight">Distribuição de Gênero</h3>
                  <p className="text-[9px] text-slate-400 font-bold uppercase">Meta Objetivo: {campaign.objective}</p>
                </div>
                <div className="h-[250px] md:h-[300px] w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <ReBarChart data={demographicChartData}>
                      <CartesianGrid vertical={false} stroke="#f1f5f9" strokeDasharray="3 3" />
                      <XAxis dataKey="age" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} dy={5} />
                      <YAxis hide />
                      <ReTooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.15)'}} />
                      <Legend verticalAlign="bottom" iconType="circle" wrapperStyle={{paddingTop: '20px', fontSize: '10px', fontWeight: '800', textTransform: 'uppercase'}} />
                      <Bar name="M" dataKey="Homens" fill="#6366f1" radius={[4, 4, 0, 0]} barSize={20} />
                      <Bar name="F" dataKey="Mulheres" fill="#2dd4bf" radius={[4, 4, 0, 0]} barSize={20} />
                    </ReBarChart>
                  </ResponsiveContainer>
                </div>
              </div>

              <section className="bg-slate-900 rounded-[32px] md:rounded-[40px] p-1 shadow-2xl">
                <div className="bg-white rounded-[30px] md:rounded-[38px] p-6 md:p-8">
                  <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
                    <div className="flex items-center gap-3">
                      <div className="bg-indigo-600 p-2 rounded-xl">
                        <Sparkles className="w-5 h-5 text-white" />
                      </div>
                      <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">IA Strategic Insight</h3>
                    </div>
                    {!analysis && !loading && (
                      <button onClick={handleAnalyze} className="w-full md:w-auto bg-slate-900 text-white text-[10px] font-black px-6 py-3 rounded-xl uppercase hover:bg-indigo-600 transition-all">Gerar Relatório</button>
                    )}
                  </div>
                  {loading ? (
                    <div className="flex flex-col items-center py-8 gap-3">
                      <Loader2 className="w-8 h-8 animate-spin text-indigo-600" />
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">Analisando segmentação e métricas...</p>
                    </div>
                  ) : analysis && (
                    <div className="bg-slate-50 p-5 md:p-8 rounded-3xl text-xs md:text-sm leading-relaxed text-slate-700 border border-slate-100 font-medium">
                      {analysis}
                    </div>
                  )}
                </div>
              </section>
            </div>
          )}

          {activeTab === 'adsets' && (
            <div className="space-y-6 animate-fade-in">
              {adSets.map(adset => (
                <div key={adset.id} className="bg-white rounded-[28px] md:rounded-[32px] border border-slate-200 shadow-sm overflow-hidden">
                  <div className="p-5 md:p-6 bg-slate-50/50 border-b border-slate-100 flex flex-col md:flex-row justify-between gap-4">
                    <div className="flex items-center gap-3">
                      <div className={`w-2.5 h-2.5 rounded-full ${adset.status === 'active' ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.4)]' : 'bg-slate-300'}`}></div>
                      <h4 className="font-black text-slate-900 text-sm md:text-base">{adset.name}</h4>
                    </div>
                    <div className="flex items-center justify-between md:justify-end gap-6">
                       <span className="text-[9px] font-black text-slate-400 bg-white px-3 py-1.5 rounded-full border border-slate-100 uppercase">ROAS: {(adset.metrics.conversionValue / (adset.metrics.spend || 1)).toFixed(2)}x</span>
                       <div className="text-right">
                          <p className="text-[8px] font-black text-slate-400 uppercase">Orçamento</p>
                          <p className="text-xs font-black text-slate-900">R$ {adset.budget?.toLocaleString('pt-BR')}</p>
                       </div>
                    </div>
                  </div>

                  <div className="p-5 md:p-6">
                    <div className="mb-6">
                      <p className="text-[10px] font-black text-slate-400 uppercase flex items-center gap-2 mb-3">
                        <Target className="w-4 h-4 text-indigo-600" /> Público Alvo
                      </p>
                      {renderAudienceDetails(adset.audience)}
                    </div>

                    <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4">
                       {[
                         { label: 'Gasto', val: `R$ ${adset.metrics.spend.toFixed(2)}` },
                         { label: 'Conv.', val: adset.metrics.messages || adset.metrics.conversions || 0 },
                         { label: 'CTR', val: `${((adset.metrics.clicks / (adset.metrics.impressions || 1)) * 100).toFixed(2)}%` },
                         { label: 'CPM', val: `R$ ${adset.metrics.cpm?.toFixed(2)}` }
                       ].map((stat, i) => (
                         <div key={i} className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                            <p className="text-[8px] font-black text-slate-400 uppercase mb-1">{stat.label}</p>
                            <p className="text-xs md:text-sm font-black text-slate-800">{stat.val}</p>
                         </div>
                       ))}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'ads' && (
            <div className="space-y-6 md:space-y-8 animate-fade-in">
              {allAds.map(ad => {
                const adCtr = ad.metrics.impressions > 0 ? ((ad.metrics.clicks / ad.metrics.impressions) * 100).toFixed(2) : '0.00';
                const adCostPerRes = (ad.metrics.messages || ad.metrics.conversions || 0) > 0 
                  ? (ad.metrics.spend / (ad.metrics.messages || ad.metrics.conversions || 1)).toFixed(2) 
                  : '0.00';

                return (
                  <div key={ad.id} className="bg-white rounded-[32px] md:rounded-[40px] border border-slate-200 overflow-hidden shadow-sm flex flex-col lg:flex-row hover:shadow-xl transition-all group border-l-4 border-l-indigo-600">
                    <div className="w-full lg:w-72 h-72 lg:h-auto bg-slate-100 relative overflow-hidden flex-shrink-0">
                      <img src={ad.creative.url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
                      <div className="absolute top-4 left-4 bg-slate-900/90 backdrop-blur-md text-white text-[8px] font-black uppercase px-2 py-1 rounded-lg shadow-xl">AD: {ad.id}</div>
                      <div className="absolute inset-0 bg-gradient-to-t from-slate-900/90 via-transparent to-transparent flex flex-col justify-end p-5">
                         <p className="text-white text-xs font-black leading-tight">{ad.creative.headline}</p>
                      </div>
                    </div>

                    <div className="flex-1 p-6 md:p-8 flex flex-col justify-between">
                      <div className="flex flex-col md:flex-row justify-between items-start gap-4 mb-6">
                         <div>
                            <h5 className="font-black text-slate-900 text-base md:text-lg mb-1">{ad.name}</h5>
                            <div className="flex items-center gap-2">
                              <span className={`w-2 h-2 rounded-full ${ad.status === 'active' ? 'bg-emerald-500' : 'bg-slate-300'}`}></span>
                              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Entrega Ativa</p>
                            </div>
                         </div>
                         <div className="md:text-right">
                            <p className="text-[8px] font-black text-slate-400 uppercase mb-0.5">CPA Individual</p>
                            <p className="text-xl md:text-2xl font-black text-indigo-600">R$ {adCostPerRes}</p>
                         </div>
                      </div>

                      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-4 mb-6">
                        {[
                          { l: 'Gasto', v: `R$ ${ad.metrics.spend.toFixed(2)}` },
                          { l: 'Resultados', v: ad.metrics.messages || ad.metrics.conversions || 0 },
                          { l: 'CTR', v: `${adCtr}%` },
                          { l: 'CPM', v: `R$ ${ad.metrics.cpm?.toFixed(2)}` }
                        ].map((stat, i) => (
                          <div key={i} className="bg-slate-50 p-3 md:p-4 rounded-2xl border border-slate-100">
                             <p className="text-[8px] font-black text-slate-400 uppercase mb-0.5">{stat.l}</p>
                             <p className="text-[11px] md:text-xs font-black text-slate-800 truncate">{stat.v}</p>
                          </div>
                        ))}
                      </div>

                      {ad.metrics.video && (
                        <div className="bg-indigo-600 rounded-[28px] p-5 md:p-6 text-white">
                          <div className="flex items-center gap-2 mb-4">
                            <Play className="w-4 h-4" />
                            <h6 className="text-[9px] font-black uppercase tracking-widest">Video Metrics</h6>
                          </div>
                          <div className="grid grid-cols-3 gap-2">
                             <div>
                                <p className="text-[7px] font-black text-indigo-200 uppercase mb-0.5">Tempo Médio</p>
                                <p className="text-[11px] font-black">{formatVideoTime(ad.metrics.video.avgTime)}</p>
                             </div>
                             <div>
                                <p className="text-[7px] font-black text-indigo-200 uppercase mb-0.5">Retenção 50%</p>
                                <p className="text-[11px] font-black">{((ad.metrics.video.retention50 / ad.metrics.video.plays) * 100).toFixed(1)}%</p>
                             </div>
                             <div>
                                <p className="text-[7px] font-black text-indigo-200 uppercase mb-0.5">VTR 100%</p>
                                <p className="text-[11px] font-black text-emerald-300">{((ad.metrics.video.retention100 / ad.metrics.video.plays) * 100).toFixed(1)}%</p>
                             </div>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { MOCK_CLIENTS } from './constants';
import { Sidebar } from './components/Sidebar';
import { StatCard } from './components/StatCard';
import { CampaignDetails } from './components/CampaignDetails';
import { SettingsModal } from './components/SettingsModal';
import { Client, Campaign } from './types';
// Added missing TrendingUp import from lucide-react
import { Search, Filter, Calendar, BarChart2, DollarSign, MousePointer, ShoppingBag, Eye, Target, RefreshCw, AlertTriangle, Menu, TrendingUp } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { syncMetaAdsData, MetaAccountInfo } from './services/metaService';

function App() {
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [selectedClientId, setSelectedClientId] = useState<string>(MOCK_CLIENTS[0].id);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);

  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  const selectedClient = clients.find(c => c.id === selectedClientId) || clients[0];

  const clientMetrics = useMemo(() => {
    if (!selectedClient) return { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 };
    return selectedClient.campaigns.reduce((acc, curr) => {
      acc.spend += curr.metrics.spend;
      acc.impressions += curr.metrics.impressions;
      acc.clicks += curr.metrics.clicks;
      acc.conversions += curr.metrics.conversions;
      acc.revenue += curr.metrics.conversionValue;
      return acc;
    }, { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 });
  }, [selectedClient]);

  const roas = clientMetrics.spend > 0 ? (clientMetrics.revenue / clientMetrics.spend).toFixed(2) : '0.00';
  const ctr = clientMetrics.impressions > 0 ? ((clientMetrics.clicks / clientMetrics.impressions) * 100).toFixed(2) : '0.00';

  const chartData = [
    { name: '01 Set', spend: clientMetrics.spend * 0.1, revenue: clientMetrics.revenue * 0.08 },
    { name: '05 Set', spend: clientMetrics.spend * 0.2, revenue: clientMetrics.revenue * 0.15 },
    { name: '10 Set', spend: clientMetrics.spend * 0.4, revenue: clientMetrics.revenue * 0.35 },
    { name: '15 Set', spend: clientMetrics.spend * 0.6, revenue: clientMetrics.revenue * 0.65 },
    { name: '20 Set', spend: clientMetrics.spend * 0.8, revenue: clientMetrics.revenue * 0.75 },
    { name: '25 Set', spend: clientMetrics.spend * 0.9, revenue: clientMetrics.revenue * 0.9 },
    { name: '30 Set', spend: clientMetrics.spend, revenue: clientMetrics.revenue },
  ];

  const handleSaveAccount = (data: { adAccountId: string; accessToken: string; accountInfo: MetaAccountInfo }) => {
    const { accessToken, accountInfo } = data;
    const officialId = accountInfo.id;

    setClients(prevClients => {
      const existingClientIndex = prevClients.findIndex(c => 
        (c.adAccountId && c.adAccountId === officialId) ||
        (editingClient && c.id === editingClient.id)
      );

      if (existingClientIndex >= 0) {
        const updatedClients = [...prevClients];
        updatedClients[existingClientIndex] = {
          ...updatedClients[existingClientIndex],
          name: accountInfo.name,
          adAccountId: officialId,
          accessToken: accessToken,
          lastSync: 'Configuração Atualizada'
        };
        setSelectedClientId(updatedClients[existingClientIndex].id);
        return updatedClients;
      } else {
        const newClient: Client = {
          id: `c_${Date.now()}`,
          name: accountInfo.name,
          industry: 'Geral',
          avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(accountInfo.name)}&background=random`,
          adAccountId: officialId,
          accessToken: accessToken,
          lastSync: 'Aguardando Sinc.',
          campaigns: []
        };
        setSelectedClientId(newClient.id);
        return [...prevClients, newClient];
      }
    });
  };

  const handleDeleteClient = (id: string) => {
    setClients(prevClients => {
      const filtered = prevClients.filter(c => c.id !== id);
      if (selectedClientId === id && filtered.length > 0) {
        setSelectedClientId(filtered[0].id);
      }
      return filtered;
    });
  };

  const handleSyncData = async () => {
    if (!selectedClient || !selectedClient.adAccountId) return;
    setIsSyncing(true);
    setSyncError(null);
    try {
      const updatedClient = await syncMetaAdsData(selectedClient);
      setClients(prevClients => 
        prevClients.map(c => c.id === updatedClient.id ? updatedClient : c)
      );
    } catch (error: any) {
      setSyncError(error.message);
      setTimeout(() => setSyncError(null), 5000);
    } finally {
      setIsSyncing(false);
    }
  };

  const openSettingsForNew = () => {
    setEditingClient(null);
    setIsSettingsOpen(true);
  };

  return (
    <div className="flex bg-slate-50 min-h-screen">
      <Sidebar 
        clients={clients} 
        selectedClientId={selectedClientId} 
        onSelectClient={setSelectedClientId} 
        onOpenSettings={openSettingsForNew}
        onDeleteClient={handleDeleteClient}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      <main className="flex-1 w-full lg:ml-64 transition-all duration-300 overflow-x-hidden">
        {/* Mobile Navbar */}
        <div className="lg:hidden flex items-center justify-between p-4 bg-white border-b border-slate-200 sticky top-0 z-30">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 hover:bg-slate-100 rounded-lg">
             <Menu className="w-6 h-6 text-slate-600" />
          </button>
          <div className="flex flex-col items-center">
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cliente Selecionado</span>
             <h4 className="text-xs font-black text-indigo-600">{selectedClient.name}</h4>
          </div>
          <button onClick={handleSyncData} className="p-2 text-indigo-600">
             <RefreshCw className={`w-5 h-5 ${isSyncing ? 'animate-spin' : ''}`} />
          </button>
        </div>

        <div className="p-4 md:p-8 space-y-8">
          <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex items-center gap-3">
                 <h1 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">Painel de Tráfego</h1>
                 {syncError && (
                   <span className="hidden md:flex items-center text-[10px] font-black text-rose-600 bg-rose-50 px-3 py-1 rounded-full border border-rose-100 uppercase">
                     <AlertTriangle className="w-3 h-3 mr-1" /> Erro
                   </span>
                 )}
              </div>
              <p className="text-xs md:text-sm text-slate-500 font-medium mt-1">
                Visualizando resultados de <span className="font-bold text-indigo-600">{selectedClient.name}</span>
              </p>
            </div>

            <div className="flex flex-wrap gap-2 w-full md:w-auto">
              <button 
                onClick={handleSyncData}
                disabled={isSyncing || !selectedClient.adAccountId}
                className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-4 py-2.5 rounded-xl text-xs font-black uppercase shadow-lg shadow-indigo-100 active:scale-95 transition-all"
              >
                <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
                {isSyncing ? 'Sincronizando' : 'Atualizar'}
              </button>
              <button className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-white border border-slate-200 text-slate-600 px-4 py-2.5 rounded-xl text-xs font-black uppercase">
                <Calendar className="w-4 h-4" /> Este Mês
              </button>
            </div>
          </header>

          {/* Quick Metrics Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
            <StatCard label="Investimento" value={`R$ ${clientMetrics.spend.toLocaleString('pt-BR')}`} trend={12} icon={<DollarSign />} />
            <StatCard label="ROAS" value={`${roas}x`} trend={-2} icon={<BarChart2 />} />
            <StatCard label="Conversões" value={clientMetrics.conversions.toString()} trend={8} icon={<ShoppingBag />} />
            <StatCard label="CTR Médio" value={`${ctr}%`} neutral icon={<MousePointer />} />
          </div>

          {/* Main Chart Section */}
          <div className="bg-white p-4 md:p-8 rounded-[32px] border border-slate-200 shadow-sm overflow-hidden">
            <div className="flex justify-between items-center mb-8">
              <h3 className="font-black text-slate-900 uppercase tracking-widest text-xs flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-indigo-600" /> Fluxo de Performance
              </h3>
            </div>
            <div className="h-[250px] md:h-[350px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                  <YAxis hide />
                  <CartesianGrid vertical={false} stroke="#f8fafc" />
                  <Tooltip contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} />
                  <Area type="monotone" dataKey="revenue" stroke="#4f46e5" fillOpacity={1} fill="url(#colorRevenue)" strokeWidth={4} />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
              <h2 className="text-xl font-black text-slate-900 tracking-tight">Campanhas Ativas</h2>
              <div className="relative w-full md:w-72">
                 <input 
                  type="text" 
                  placeholder="Filtrar campanha..." 
                  className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl text-xs font-bold focus:outline-none focus:ring-2 focus:ring-indigo-500 shadow-sm"
                 />
                 <Search className="w-4 h-4 text-slate-400 absolute left-3.5 top-1/2 -translate-y-1/2" />
              </div>
            </div>

            {selectedClient.campaigns.length === 0 ? (
              <div className="bg-white rounded-3xl p-12 text-center border-2 border-slate-100 border-dashed">
                <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Nenhuma campanha encontrada para este cliente.</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-4 md:gap-6">
                {selectedClient.campaigns.map((campaign) => (
                  <div 
                    key={campaign.id} 
                    onClick={() => setSelectedCampaign(campaign)}
                    className="bg-white rounded-[28px] border border-slate-200 shadow-sm hover:shadow-xl hover:border-indigo-300 transition-all cursor-pointer group flex flex-col sm:flex-row overflow-hidden"
                  >
                    <div className="w-full sm:w-44 h-44 sm:h-auto bg-slate-100 flex-shrink-0 relative overflow-hidden">
                      <img src={campaign.creative.url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                      <span className="absolute top-3 left-3 bg-slate-900 text-white text-[8px] font-black px-2 py-1 rounded-lg uppercase tracking-widest">{campaign.platform}</span>
                    </div>

                    <div className="p-6 flex-1 flex flex-col justify-between bg-white">
                      <div>
                        <div className="flex justify-between items-start mb-2 gap-2">
                          <h3 className="font-black text-slate-900 text-sm group-hover:text-indigo-600 transition-colors line-clamp-1">{campaign.name}</h3>
                          <span className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase flex-shrink-0 ${campaign.status === 'active' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}>
                            {campaign.status}
                          </span>
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase flex items-center gap-1 mb-4">
                          <Target className="w-3 h-3 text-indigo-500" /> {campaign.objective}
                        </p>

                        <div className="grid grid-cols-3 gap-2 pt-4 border-t border-slate-50">
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">Gasto</p>
                            <p className="font-black text-slate-900 text-xs">R$ {campaign.metrics.spend.toLocaleString('pt-BR')}</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">ROAS</p>
                            <p className="font-black text-indigo-600 text-xs">{(campaign.metrics.conversionValue / (campaign.metrics.spend || 1)).toFixed(1)}x</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">CTR</p>
                            <p className="font-black text-slate-900 text-xs">{((campaign.metrics.clicks / (campaign.metrics.impressions || 1)) * 100).toFixed(1)}%</p>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </main>

      {selectedCampaign && (
        <CampaignDetails 
          campaign={selectedCampaign} 
          onClose={() => setSelectedCampaign(null)} 
        />
      )}

      <SettingsModal
        initialClient={editingClient}
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        onSave={handleSaveAccount}
      />
    </div>
  );
}

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Calendar, ChevronDown } from 'lucide-react';

export type DatePreset = 
  | 'maximum' | 'today' | 'yesterday' | 'today_and_yesterday' 
  | 'last_7d' | 'last_14d' | 'last_28d' | 'last_30d' 
  | 'this_week' | 'last_week' | 'this_month' | 'last_month' 
  | 'custom';

interface DateRangePickerProps {
  selected: DatePreset;
  onSelect: (preset: DatePreset) => void;
}

const PRESETS: { id: DatePreset; label: string }[] = [
  { id: 'maximum', label: 'Máximo' },
  { id: 'today', label: 'Hoje' },
  { id: 'yesterday', label: 'Ontem' },
  { id: 'today_and_yesterday', label: 'Hoje e ontem' },
  { id: 'last_7d', label: 'Últimos 7 dias' },
  { id: 'last_14d', label: 'Últimos 14 dias' },
  { id: 'last_28d', label: 'Últimos 28 dias' },
  { id: 'last_30d', label: 'Últimos 30 dias' },
  { id: 'this_week', label: 'Esta semana' },
  { id: 'last_week', label: 'Semana passada' },
  { id: 'this_month', label: 'Este mês' },
  { id: 'last_month', label: 'Mês passado' },
  { id: 'custom', label: 'Personalizado' },
];

export const DateRangePicker: React.FC<DateRangePickerProps> = ({ selected, onSelect }) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const selectedLabel = PRESETS.find(p => p.id === selected)?.label || 'Período';

  return (
    <div className="relative" ref={containerRef}>
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center gap-2 bg-white border border-slate-200 text-slate-600 px-4 py-2.5 rounded-xl text-xs font-black uppercase shadow-sm hover:border-indigo-300 transition-all whitespace-nowrap"
      >
        <Calendar className="w-4 h-4 text-indigo-600" />
        {selectedLabel}
        <ChevronDown className={`w-3 h-3 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute right-0 mt-2 w-64 bg-white border border-slate-200 rounded-2xl shadow-2xl z-[100] py-4 animate-fade-in-up">
          <div className="px-6 pb-2 mb-2 border-b border-slate-100">
            <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Usados recentemente</h4>
          </div>
          <div className="max-h-[400px] overflow-y-auto custom-scrollbar">
            {PRESETS.map((preset) => (
              <label 
                key={preset.id}
                className="flex items-center px-6 py-2.5 hover:bg-slate-50 cursor-pointer transition-colors group"
              >
                <div className="relative flex items-center justify-center mr-3">
                  <input 
                    type="radio" 
                    name="date-preset"
                    className="appearance-none w-5 h-5 border-2 border-slate-300 rounded-full checked:border-indigo-600 transition-all"
                    checked={selected === preset.id}
                    onChange={() => {
                      onSelect(preset.id);
                      setIsOpen(false);
                    }}
                  />
                  {selected === preset.id && (
                    <div className="absolute w-2.5 h-2.5 bg-indigo-600 rounded-full" />
                  )}
                </div>
                <span className={`text-sm font-semibold transition-colors ${selected === preset.id ? 'text-slate-900' : 'text-slate-500 group-hover:text-slate-700'}`}>
                  {preset.label}
                </span>
              </label>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

import { Client, Campaign, AdSet, Ad, Metrics, Creative, DemographicData, VideoMetrics } from "../types";

export interface MetaAccountInfo {
  id: string;
  name: string;
  currency: string;
}

const getActionValue = (actions: any[], actionType: string): number => {
  if (!actions || !Array.isArray(actions)) return 0;
  const action = actions.find((a: any) => a.action_type === actionType);
  return action ? parseFloat(action.value || action.count || 0) : 0;
};

const mapInsightsToMetrics = (insightsData: any): Metrics => {
  const insights = insightsData?.data?.[0] || {};
  const actions = insights.actions || [];

  const messages = getActionValue(actions, 'onsite_conversion.messaging_first_reply');
  const spend = parseFloat(insights.spend || 0);

  const video: VideoMetrics = {
    plays: getActionValue(actions, 'video_play'),
    avgTime: parseFloat(insights.video_avg_time_watched_actions?.[0]?.value || 0),
    retention25: getActionValue(actions, 'video_p25_watched_actions'),
    retention50: getActionValue(actions, 'video_p50_watched_actions'),
    retention75: getActionValue(actions, 'video_p75_watched_actions'),
    retention100: getActionValue(actions, 'video_p100_watched_actions'),
  };

  return {
    spend,
    impressions: parseInt(insights.impressions || 0),
    reach: parseInt(insights.reach || 0),
    frequency: parseFloat(insights.frequency || 0),
    cpm: parseFloat(insights.cpm || 0),
    clicks: parseInt(insights.clicks || 0),
    conversions: getActionValue(actions, 'purchase'),
    conversionValue: getActionValue(insights.action_values, 'purchase'),
    messages,
    costPerMessage: messages > 0 ? spend / messages : 0,
    video: video.plays > 0 ? video : undefined
  };
};

export const validateMetaConnection = async (adAccountId: string, accessToken: string): Promise<MetaAccountInfo> => {
  const cleanActId = adAccountId.replace('act_', '').trim();
  const url = `https://graph.facebook.com/v19.0/act_${cleanActId}?fields=name,currency&access_token=${accessToken}`;
  const response = await fetch(url);
  const json = await response.json();
  if (json.error) throw new Error(json.error.message);
  return { id: json.id, name: json.name, currency: json.currency };
};

export const syncMetaAdsData = async (client: Client, datePreset: string = 'this_month'): Promise<Client> => {
  if (!client.adAccountId || !client.accessToken) throw new Error("Credenciais ausentes.");
  const accountId = client.adAccountId.startsWith('act_') ? client.adAccountId : `act_${client.adAccountId}`;
  const token = client.accessToken;

  const insightsFields = 'spend,impressions,reach,frequency,cpm,clicks,actions,action_values,video_avg_time_watched_actions';

  try {
    const url = `https://graph.facebook.com/v19.0/${accountId}/campaigns?fields=id,name,status,objective,daily_budget,lifetime_budget,start_time,stop_time,insights{${insightsFields}},adsets{id,name,status,daily_budget,lifetime_budget,targeting,insights{${insightsFields}},ads{id,name,status,creative{id,title,image_url,thumbnail_url},insights{${insightsFields}}}}&date_preset=${datePreset}&access_token=${token}`;

    const response = await fetch(url);
    const json = await response.json();
    if (json.error) throw new Error(json.error.message);

    const campaigns: Campaign[] = await Promise.all(json.data.map(async (fbCamp: any) => {
      const demoUrl = `https://graph.facebook.com/v19.0/${fbCamp.id}/insights?breakdowns=age,gender&fields=spend,actions&date_preset=${datePreset}&access_token=${token}`;
      const demoRes = await fetch(demoUrl);
      const demoJson = await demoRes.json();

      const demographics: DemographicData[] = (demoJson.data || []).map((d: any) => ({
        age: d.age,
        gender: d.gender,
        spend: parseFloat(d.spend || 0),
        results: getActionValue(d.actions, fbCamp.objective === 'MESSAGES' ? 'onsite_conversion.messaging_first_reply' : 'purchase')
      }));

      const campMetrics = { ...mapInsightsToMetrics(fbCamp.insights), demographics };

      const adSets: AdSet[] = (fbCamp.adsets?.data || []).map((fbAdSet: any) => {
        const ads: Ad[] = (fbAdSet.ads?.data || []).map((fbAd: any) => ({
          id: fbAd.id,
          name: fbAd.name,
          status: fbAd.status === 'ACTIVE' ? 'active' : 'paused',
          creative: {
            id: fbAd.creative?.id || '0',
            type: 'image',
            url: fbAd.creative?.image_url || fbAd.creative?.thumbnail_url || 'https://via.placeholder.com/150',
            headline: fbAd.creative?.title || fbAd.name
          },
          metrics: mapInsightsToMetrics(fbAd.insights)
        }));

        return {
          id: fbAdSet.id,
          name: fbAdSet.name,
          status: fbAdSet.status === 'ACTIVE' ? 'active' : 'paused',
          budget: parseFloat(fbAdSet.daily_budget || fbAdSet.lifetime_budget || 0) / 100,
          budgetType: fbAdSet.daily_budget ? 'DAILY' : 'LIFETIME',
          audience: JSON.stringify(fbAdSet.targeting),
          metrics: mapInsightsToMetrics(fbAdSet.insights),
          ads
        };
      });

      return {
        id: fbCamp.id,
        name: fbCamp.name,
        status: fbCamp.status === 'ACTIVE' ? 'active' : 'paused',
        platform: 'facebook',
        objective: fbCamp.objective,
        metrics: campMetrics,
        budget: parseFloat(fbCamp.daily_budget || fbCamp.lifetime_budget || 0) / 100,
        budgetType: fbCamp.daily_budget ? 'DAILY' : 'LIFETIME',
        startTime: fbCamp.start_time,
        endTime: fbCamp.stop_time,
        adSets,
        creative: adSets[0]?.ads[0]?.creative || { id: '0', type: 'image', url: '', headline: '' },
        audience: 'Múltiplos Públicos'
      };
    }));

    return { ...client, lastSync: new Date().toLocaleTimeString(), campaigns };
  } catch (e: any) {
    throw e;
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { MOCK_CLIENTS } from './constants';
import { Sidebar } from './components/Sidebar';
import { StatCard } from './components/StatCard';
import { CampaignDetails } from './components/CampaignDetails';
import { SettingsModal } from './components/SettingsModal';
import { DateRangePicker, DatePreset } from './components/DateRangePicker';
import { Client, Campaign } from './types';
import { Search, Filter, Calendar, BarChart2, DollarSign, MousePointer, ShoppingBag, Eye, Target, RefreshCw, AlertTriangle, Menu, TrendingUp } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { syncMetaAdsData, MetaAccountInfo } from './services/metaService';

function App() {
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [selectedClientId, setSelectedClientId] = useState<string>(MOCK_CLIENTS[0].id);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);

  const [datePreset, setDatePreset] = useState<DatePreset>('this_month');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);

  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  const selectedClient = clients.find(c => c.id === selectedClientId) || clients[0];

  const clientMetrics = useMemo(() => {
    if (!selectedClient) return { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 };
    return selectedClient.campaigns.reduce((acc, curr) => {
      acc.spend += curr.metrics.spend;
      acc.impressions += curr.metrics.impressions;
      acc.clicks += curr.metrics.clicks;
      acc.conversions += curr.metrics.conversions;
      acc.revenue += curr.metrics.conversionValue;
      return acc;
    }, { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 });
  }, [selectedClient]);

  const roas = clientMetrics.spend > 0 ? (clientMetrics.revenue / clientMetrics.spend).toFixed(2) : '0.00';
  const ctr = clientMetrics.impressions > 0 ? ((clientMetrics.clicks / clientMetrics.impressions) * 100).toFixed(2) : '0.00';

  const chartData = [
    { name: 'Início', spend: clientMetrics.spend * 0.1, revenue: clientMetrics.revenue * 0.08 },
    { name: '1/4 Período', spend: clientMetrics.spend * 0.3, revenue: clientMetrics.revenue * 0.25 },
    { name: 'Metade', spend: clientMetrics.spend * 0.6, revenue: clientMetrics.revenue * 0.55 },
    { name: 'Fim', spend: clientMetrics.spend, revenue: clientMetrics.revenue },
  ];

  const handleSyncData = async (presetOverride?: DatePreset) => {
    if (!selectedClient || !selectedClient.adAccountId) return;
    setIsSyncing(true);
    setSyncError(null);
    try {
      const updatedClient = await syncMetaAdsData(selectedClient, presetOverride || datePreset);
      setClients(prevClients => 
        prevClients.map(c => c.id === updatedClient.id ? updatedClient : c)
      );
    } catch (error: any) {
      setSyncError(error.message);
      setTimeout(() => setSyncError(null), 5000);
    } finally {
      setIsSyncing(false);
    }
  };

  // Re-sync when date preset changes
  useEffect(() => {
    if (selectedClient.adAccountId && selectedClient.accessToken) {
       handleSyncData(datePreset);
    }
  }, [datePreset, selectedClientId]);

  const handleSaveAccount = (data: { adAccountId: string; accessToken: string; accountInfo: MetaAccountInfo }) => {
    const { accessToken, accountInfo } = data;
    const officialId = accountInfo.id;

    setClients(prevClients => {
      const existingClientIndex = prevClients.findIndex(c => 
        (c.adAccountId && c.adAccountId === officialId) ||
        (editingClient && c.id === editingClient.id)
      );

      if (existingClientIndex >= 0) {
        const updatedClients = [...prevClients];
        updatedClients[existingClientIndex] = {
          ...updatedClients[existingClientIndex],
          name: accountInfo.name,
          adAccountId: officialId,
          accessToken: accessToken,
          lastSync: 'Configuração Atualizada'
        };
        setSelectedClientId(updatedClients[existingClientIndex].id);
        return updatedClients;
      } else {
        const newClient: Client = {
          id: `c_${Date.now()}`,
          name: accountInfo.name,
          industry: 'Geral',
          avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(accountInfo.name)}&background=random`,
          adAccountId: officialId,
          accessToken: accessToken,
          lastSync: 'Aguardando Sinc.',
          campaigns: []
        };
        setSelectedClientId(newClient.id);
        return [...prevClients, newClient];
      }
    });
  };

  const handleDeleteClient = (id: string) => {
    setClients(prevClients => {
      const filtered = prevClients.filter(c => c.id !== id);
      if (selectedClientId === id && filtered.length > 0) {
        setSelectedClientId(filtered[0].id);
      }
      return filtered;
    });
  };

  const openSettingsForNew = () => {
    setEditingClient(null);
    setIsSettingsOpen(true);
  };

  return (
    <div className="flex bg-slate-50 min-h-screen">
      <Sidebar 
        clients={clients} 
        selectedClientId={selectedClientId} 
        onSelectClient={setSelectedClientId} 
        onOpenSettings={openSettingsForNew}
        onDeleteClient={handleDeleteClient}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      <main className="flex-1 w-full lg:ml-64 transition-all duration-300 overflow-x-hidden">
        {/* Mobile Navbar */}
        <div className="lg:hidden flex items-center justify-between p-4 bg-white border-b border-slate-200 sticky top-0 z-30">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 hover:bg-slate-100 rounded-lg">
             <Menu className="w-6 h-6 text-slate-600" />
          </button>
          <div className="flex flex-col items-center">
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cliente Selecionado</span>
             <h4 className="text-xs font-black text-indigo-600">{selectedClient.name}</h4>
          </div>
          <button onClick={() => handleSyncData()} className="p-2 text-indigo-600">
             <RefreshCw className={`w-5 h-5 ${isSyncing ? 'animate-spin' : ''}`} />
          </button>
        </div>

        <div className="p-4 md:p-8 space-y-8">
          <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex items-center gap-3">
                 <h1 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">Painel de Tráfego</h1>
                 {syncError && (
                   <span className="hidden md:flex items-center text-[10px] font-black text-rose-600 bg-rose-50 px-3 py-1 rounded-full border border-rose-100 uppercase">
                     <AlertTriangle className="w-3 h-3 mr-1" /> Erro
                   </span>
                 )}
              </div>
              <p className="text-xs md:text-sm text-slate-500 font-medium mt-1">
                Analisando <span className="font-bold text-indigo-600">{selectedClient.name}</span>
              </p>
            </div>

            <div className="flex flex-wrap gap-2 w-full md:w-auto">
              <button 
                onClick={() => handleSyncData()}
                disabled={isSyncing || !selectedClient.adAccountId}
                className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-4 py-2.5 rounded-xl text-xs font-black uppercase shadow-lg shadow-indigo-100 active:scale-95 transition-all"
              >
                <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
                {isSyncing ? 'Carregando' : 'Sincronizar'}
              </button>
              <DateRangePicker 
                selected={datePreset} 
                onSelect={setDatePreset} 
              />
            </div>
          </header>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
            <StatCard label="Investimento" value={`R$ ${clientMetrics.spend.toLocaleString('pt-BR')}`} trend={12} icon={<DollarSign />} />
            <StatCard label="ROAS" value={`${roas}x`} trend={-2} icon={<BarChart2 />} />
            <StatCard label="Conversões" value={clientMetrics.conversions.toString()} trend={8} icon={<ShoppingBag />} />
            <StatCard label="CTR Médio" value={`${ctr}%`} neutral icon={<MousePointer />} />
          </div>

          <div className="bg-white p-4 md:p-8 rounded-[32px] border border-slate-200 shadow-sm overflow-hidden">
            <div className="flex justify-between items-center mb-8">
              <h3 className="font-black text-slate-900 uppercase tracking-widest text-xs flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-indigo-600" /> Curva de Performance ({datePreset.replace('_', ' ')})
              </h3>
            </div>
            <div className="h-[250px] md:h-[350px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                  <YAxis hide />
                  <CartesianGrid vertical={false} stroke="#f8fafc" />
                  <Tooltip contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} />
                  <Area type="monotone" dataKey="revenue" stroke="#4f46e5" fillOpacity={1} fill="url(#colorRevenue)" strokeWidth={4} />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
              <h2 className="text-xl font-black text-slate-900 tracking-tight">Campanhas no Período</h2>
              <div className="relative w-full md:w-72">
                 <input 
                  type="text" 
                  placeholder="Filtrar campanha..." 
                  className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl text-xs font-bold focus:outline-none focus:ring-2 focus:ring-indigo-500 shadow-sm"
                 />
                 <Search className="w-4 h-4 text-slate-400 absolute left-3.5 top-1/2 -translate-y-1/2" />
              </div>
            </div>

            {selectedClient.campaigns.length === 0 ? (
              <div className="bg-white rounded-3xl p-12 text-center border-2 border-slate-100 border-dashed">
                <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Sem campanhas para este período.</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-4 md:gap-6">
                {selectedClient.campaigns.map((campaign) => (
                  <div 
                    key={campaign.id} 
                    onClick={() => setSelectedCampaign(campaign)}
                    className="bg-white rounded-[28px] border border-slate-200 shadow-sm hover:shadow-xl hover:border-indigo-300 transition-all cursor-pointer group flex flex-col sm:flex-row overflow-hidden"
                  >
                    <div className="w-full sm:w-44 h-44 sm:h-auto bg-slate-100 flex-shrink-0 relative overflow-hidden">
                      <img src={campaign.creative.url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                      <span className="absolute top-3 left-3 bg-slate-900 text-white text-[8px] font-black px-2 py-1 rounded-lg uppercase tracking-widest">{campaign.platform}</span>
                    </div>

                    <div className="p-6 flex-1 flex flex-col justify-between bg-white">
                      <div>
                        <div className="flex justify-between items-start mb-2 gap-2">
                          <h3 className="font-black text-slate-900 text-sm group-hover:text-indigo-600 transition-colors line-clamp-1">{campaign.name}</h3>
                          <span className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase flex-shrink-0 ${campaign.status === 'active' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}>
                            {campaign.status}
                          </span>
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase flex items-center gap-1 mb-4">
                          <Target className="w-3 h-3 text-indigo-500" /> {campaign.objective}
                        </p>

                        <div className="grid grid-cols-3 gap-2 pt-4 border-t border-slate-50">
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">Gasto</p>
                            <p className="font-black text-slate-900 text-xs">R$ {campaign.metrics.spend.toLocaleString('pt-BR')}</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">ROAS</p>
                            <p className="font-black text-indigo-600 text-xs">{(campaign.metrics.conversionValue / (campaign.metrics.spend || 1)).toFixed(1)}x</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">CTR</p>
                            <p className="font-black text-slate-900 text-xs">{((campaign.metrics.clicks / (campaign.metrics.impressions || 1)) * 100).toFixed(1)}%</p>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </main>

      {selectedCampaign && (
        <CampaignDetails 
          campaign={selectedCampaign} 
          onClose={() => setSelectedCampaign(null)} 
        />
      )}

      <SettingsModal
        initialClient={editingClient}
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        onSave={handleSaveAccount}
      />
    </div>
  );
}

export default App;
